hard.solution:
function repl() {
  const rl = require('readline').createInterface({input: process.stdin, output: process.stdout});
  const prompt = () => rl.question('>>> ', i => {
    if (i==='exit'||i==='quit') return rl.close();
    try { const r = eval(i); if (r !== undefined) console.log(r); } catch(e) { console.log('Error:', e.message); }
    prompt();
  });
  prompt();
}

